var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"주인님! 부르셨슴까!! ......으아앗!","JPN":"ご主人様！　お呼びっすか！！　……うああ！","ENG":"Did you call me, sir? ... Wah!","TWN":"主人！叫我了唷！！……啊啊啊！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L15_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"아으으...... 죄송함다! 앞이 안 보여서 넘어졌슴다.","JPN":"ううっ……すみません！　前が見えなくて転んじゃいました。","ENG":"Aww... My apologies, sir. I tripped because I didn't look where I was going.","TWN":"哎喲……對不起唷！我不小心摔了一跤了唷。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"주인님이 찾는다니까, 신나서 걷고 있던 이불을 그대로 안고 와버렸지 말임다! 헤헤에......","JPN":"ご主人様がお呼びだっていうから、浮かれて畳んでた布団をそのまま持ってきちゃったっす！　へへぇ……","ENG":"I got so excited to see you that I forgot to drop off this line-dried comforter before I came. Teehee!","TWN":"我聽到主人在找我，一著急就把手上的被子也抱過來了唷！嘿嘿嘿……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"앗! 주인님! 그러고 보니 무지 피곤해보이심다! 이렇게 된 김에 얼른 베개도 가져오겠슴다!","JPN":"あっ！　ご主人様！　なんだかめちゃくちゃ疲れてるみたいっすね！　こうなったら、枕もすぐ持ってくるっす！","ENG":"Ah, sir, you look terribly exhausted. Let me bring you a pillow, too!","TWN":"啊！主人！您看起來很疲憊唷！我去把枕頭也給你抱過來唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"사양하지 않으셔도 됨다! 모네표 이불! 완전 뽀송뽀송하고 해님냄새 나서 기분 좋지 말임다!","JPN":"遠慮しないでください！　モネがお手入れした布団！　ふわふわで太陽の香りがして気持ちいいっす！","ENG":"Please, I insist, sir. Try Mone's comforter. It smells clean and fresh, just like sunshine!","TWN":"不用不好意思唷！莫妮的被子！軟綿綿的，特別舒服唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"잠깐만 누워있으면 주인님의 피로도 금방 가실 검다!","JPN":"少しだけ横になっていると、ご主人様の疲れもすぐとれると思うっす！","ENG":"Just lie down for a while, sir. You'll feel refreshed in no time!","TWN":"躺下來休息一會，主人的疲勞馬上會消散唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"보십셔! 이렇게 안고 있기만 해도 잠이 솔솔......","JPN":"見てください！　こうやって抱いているだけで眠くなる……","ENG":"Look, just holding this comforter makes me... Zzz...","TWN":"您看，只要這樣抱著就……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"......드르렁-","JPN":"……ぐうー。","ENG":".... Groarghhhrr...","TWN":"……呼嚕——"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L25_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"쿠우-울......","JPN":"スースー……","ENG":"Zzzzzlllppp...","TWN":"呼——嚕……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"......핫!","JPN":"……はっ！","ENG":"... Wah!","TWN":"……哈啊！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"엄청난 숙면 효과에 당해버렸슴다! 면목없슴다!","JPN":"超熟睡効果にやられちゃったっす！　申しわけありません！","ENG":"I couldn't resist its comforting feel! I'm ashamed, sir!","TWN":"助眠效果太強大了唷！不好意思唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"앗! 그런데 이거, 베개가 아님다! 주인님이 모네가 잠든 동안 무릎베개까지 해주신 검까!","JPN":"あっ！　でもこれ、枕じゃないっす！　ご主人様、モネが寝ている間に膝枕をしてくれたんすか！","ENG":"Ah, but this isn't a pillow... Oh my, sir! Did you let me sleep on your lap?","TWN":"啊！奇怪，這不是枕頭了唷！是主人在莫妮睡覺時枕您的大腿的唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"역시 주인님은 친절하심다! 모네 또 감동 먹었슴다!","JPN":"やっぱご主人様は優しいですね！　モネ、また感動しちゃったっす！","ENG":"You're so kind, sir! Mone is touched, again!","TWN":"主人果然很溫柔唷！莫妮又被感動了唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"그, 그런데 주인님 무릎 엄청 축축함다...... 저 때문에......","JPN":"と、ところでご主人様の膝がすっげー濡れてるっす……モネのせいで……","ENG":"B-by the way, sir, erm... your lap... It's pretty wet. I'm sorry.","TWN":"可、可是主人的大腿被弄濕了唷……都怪我……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"스읍...... 걱정마십셔! 빨래담당 모네에게 침자국 지우는 건 일도 아님다!","JPN":"……ご心配なく！　モネは洗濯担当なので、よだれの跡を消すのは簡単っす！","ENG":"*Slurp* Worry not! Drool stains are not a problem for the professional laundress, Mone!","TWN":"嗯……不用擔心唷！對洗衣高手莫妮來說，口水痕跡算不了什麼唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"뭣보다 모네는 주인님의 친절함을 모두에게 널리 알려야 한다고 생각함다! 자랑하고 싶슴다!","JPN":"何よりも、モネはご主人様の優しさをみんなに伝えるべきだと思います！　自慢したいっす！","ENG":"Most of all, Mone would like to spread my master's kindness to everyone I knows. I'm so proud of you, sir!","TWN":"比起這個，莫妮想讓所有人都知道主人有多麼溫柔唷！我想到處炫耀唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"엥? 무릎베개는 꼭 비밀로......? 정체를 숨기고 계신 검까?","JPN":"えっ？膝枕のことは絶対秘密だ……？　正体を隠してるんすか？","ENG":"Huh? Don't tell anyone about sleeping on your lap? Are you hiding your identity to everyone else, sir?","TWN":"嗯？枕大腿的事情要保密……？主人想要隱藏身份唷？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"모네는 잘은 모르겠지만, 주인님 부탁이라면 당연히 지켜드려야지 말임다!","JPN":"モネにはよくわからないっすけど、ご主人様のお願いならもちろん守るっす！","ENG":"Whatever your reason, sir, your secret is safe with Mone.","TWN":"莫妮雖然不太清楚，但既然是主人要求的，我一定會保密唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"주인님의 비밀이 퍼지지 않게 간수하는 건 메이드의 소양이라 배웠슴다! 주인님과 쭉 함께 지내려면 이 정도는 기본이지 말임다!","JPN":"ご主人様の秘密がばれないように注意するのは、メイドの素養だと教わったんす！　ご主人様とずっとご一緒するには、これぐらいは基本っすよ！","ENG":"I know that we maids must not disclose our masters' secrets. I won't break your trust, sir. I want to stay with you for as long as I can.","TWN":"保護主人的秘密是女僕的基本素養唷！和主人在一起這些都是最基本的唷！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"언제나처럼 곁을 지켜드리는 거라면 두 말 할 것 없고 말임다! 헤헤-","JPN":"いつもどおりそばで守ることなら、言うまでもないっす！　へへー。","ENG":"I also want to take good care of you from your side, sir. Teehee!","TWN":"當然還有始終陪伴在您的身邊唷！嘿嘿~"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};